public:
    vector<string> sortPeople(vector<string>& names, vector<int>& heights) {
        vector<pair<int,string>> v;
        int n = names.size();
        for(int i=0;i<n;++i) v.emplace_back(heights[i], names[i]);
        sort(v.rbegin(), v.rend());
        vector<string> res;
        for(auto& p: v) res.push_back(p.second);
